import arrow from "./arrow.svg";
import {
  LandingPage,
  Heading,
  Arrow,
  Fade,
} from "./landing.style";
import {
  ScrollLanding,
  ScrollUp,
} from "./scroll.style"
import { Page } from "./webpage.style";

function App() {
  return (
    <>
        <ScrollLanding id="landing" href="#page">
          <LandingPage className="landing-page">
            <Heading> e g a &nbsp; c h e u n g </Heading>
            <Arrow tabIndex={-1} src={arrow} alt="arrow" />
          </LandingPage>
        </ScrollLanding>
      <Page id="page">
        <ScrollUp href="#landing"></ScrollUp>
      </Page>
    </>
  );
}

export default App;
